module RefModule (  
    input wire [15:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge we or posedge dbg_halt) begin  
        memory <= data_in;  
    end  

    always @(posedge re) begin  
        data_out <= memory;  
    end  
endmodule
